create table dirkspzm32.cal_appointment_types (
    id          number(*, 0) not null enable,
    name        varchar2(50 char) not null enable,
    app_type    varchar2(50 char),
    description varchar2(255 char)
);

alter table dirkspzm32.cal_appointment_types
    add constraint pk_cal_appointment_types_id primary key ( id )
        using index enable;

alter table dirkspzm32.cal_appointment_types add constraint uk_app_type unique ( app_type )
    using index enable;


